import axios from "axios";
class ApiService {
  constructor() {
    this.baseURL = window.JCA_LOCATIONDEVIS_CONFIG?.apiBaseUrl;
    this.token = window.JCA_LOCATIONDEVIS_CONFIG?.token || "";
    this.axios = axios.create({
      baseURL: this.baseURL,
      timeout: 15000,
      headers: {
        "Content-Type": "application/json",
        "X-Requested-With": "XMLHttpRequest"
      }
    });
    this.axios.interceptors.request.use(config => {
      if (this.token) {
        config.headers.Authorization = `Bearer ${this.token}`;
      }
      return config;
    }, error => Promise.reject(error));
    this.axios.interceptors.response.use(response => response, error => {
      if (error.response) {
        const status = error.response.status;
        if (status === 401) {
          console.error("Token invalide ou expire");
        } else if (status === 403) {
          console.error("Acces refuse");
        } else if (status === 404) {
          console.error("Endpoint non trouve");
        } else if (status >= 500) {
          console.error("Erreur serveur");
        }
      }
      return Promise.reject(error);
    });
  }
  async request(action, entity, data = {}) {
    try {
      const payload = {
        action,
        entity,
        data
      };
      const response = await this.axios.post('', payload);
      return response.data;
    } catch (error) {
      if (error.request) {
        throw new Error("Erreur de connexion au serveur PrestaShop");
      }
      throw error;
    }
  }
}
export default new ApiService();
